// 自动模式：读取偏好图谱，构建推荐请求
const prefs = $input.first().json;
// 如果有手动指定的书，直接使用
const manualBook = $('🖐 手动指定书籍').first().json.body?.book;
const manualAuthor = $('🖐 手动指定书籍').first().json.body?.author;

if (manualBook) {
  return {
    mode: 'manual',
    book: manualBook,
    author: manualAuthor || ''
  };
}

// 自动模式：将偏好图谱传给 DeepSeek 做推荐
return {
  mode: 'auto',
  preferences: prefs,
  recommended: true
};

// 将 DeepSeek 返回的 JSON 填充到 Markdown 模板中
const bookData = $input.first().json.choices[0].message.content;
const parsed = typeof bookData === 'string' ? JSON.parse(bookData) : bookData;

const date = new Date().toISOString().split('T')[0];

// 构建 tags 数组 JSON 字符串
const tagsJson = JSON.stringify(parsed.tags || []);
const nextJson = JSON.stringify(parsed.next_suggestions || []);

// 填充 5 个知识点
const kp = parsed.key_points || [];

const markdown = `---
title: "📖 《${parsed.book_title}》——${parsed.one_line_summary || ''}"
author: ${parsed.author || ''}
category: ${parsed.category || ''}
tags: ${tagsJson}
date: ${date}
source: auto
next_suggestion: ${nextJson}
---

# 📖 《${parsed.book_title}》——${parsed.one_line_summary || ''}

> **为什么推荐这本书？** ${parsed.recommendation_reason || ''}

---

## 🎯 核心框架

${parsed.core_framework || ''}

---

## 📌 五个核心知识点

### 1️⃣ ${kp[0]?.title || ''}

${kp[0]?.content || ''}

> 🔑 **关键洞见：** ${kp[0]?.insight || ''}

🫁 **试试看：** ${kp[0]?.practice || ''}

### 2️⃣ ${kp[1]?.title || ''}

${kp[1]?.content || ''}

> 🔑 **关键洞见：** ${kp[1]?.insight || ''}

🫁 **试试看：** ${kp[1]?.practice || ''}

### 3️⃣ ${kp[2]?.title || ''}

${kp[2]?.content || ''}

> 🔑 **关键洞见：** ${kp[2]?.insight || ''}

🫁 **试试看：** ${kp[2]?.practice || ''}

### 4️⃣ ${kp[3]?.title || ''}

${kp[3]?.content || ''}

> 🔑 **关键洞见：** ${kp[3]?.insight || ''}

🫁 **试试看：** ${kp[3]?.practice || ''}

### 5️⃣ ${kp[4]?.title || ''}

${kp[4]?.content || ''}

> 🔑 **关键洞见：** ${kp[4]?.insight || ''}

🫁 **试试看：** ${kp[4]?.practice || ''}

---

## 💎 一句话记住这本书

> ${parsed.golden_quote || ''}

---

## 🛠️ 今日行动清单

${(parsed.action_items || []).map(item => `- [ ] ${item}`).join('\n')}

---

## 📎 关联推荐

| 方向 | 推荐书籍 | 为什么关联 |
|------|---------|-----------|
${(parsed.next_suggestions || []).map(s => `| ${s.direction === '横向拓展' ? '🔄 横向拓展' : s.direction === '深度延伸' ? '↗️ 深度延伸' : '➡️ 实用落地'} | 《${s.book}》 | ${s.reason} |`).join('\n')}

---
*generated by 拆书工作流 · ${date}*`;

const safeFileName = parsed.book_title.replace(/[\\/:*?"<>|]/g, '-');

return {
  book_title: parsed.book_title,
  author: parsed.author,
  tags: parsed.tags,
  category: parsed.category,
  next_suggestions: parsed.next_suggestions,
  markdown: markdown,
  file_name: `${date} 《${safeFileName}》拆书`,
  date: date
};

const { execSync } = require('child_process');
const dir = '/Users/a123/Documents/Obsidian Vault/拆书';
const data = JSON.stringify({ book_title: $json.book_title, tags: $json.tags, category: $json.category, next_suggestions: $json.next_suggestions });
const cmd = `cd "${dir}" && node scripts/recommendation-engine.js update '${data}'`;
try {
  const out = execSync(cmd, { encoding: 'utf-8', maxBuffer: 10 * 1024 * 1024 });
  return { success: true, output: out };
} catch (e) {
  return { success: false, error: e.message };
}

